mapper.select:
SELECT
s.id,
s.video_id,
s.comment_id,
s.like_count,
s.reply_count,
s.hot_score,
s.create_time,
s.update_time
FROM tb_comment_stats s
INNER JOIN tb_comment c ON c.id = s.comment_id
WHERE s.video_id = #{videoId}
AND c.root_id = 0
AND c.is_deleted = 0


    AND COALESCE(c.is_top, 0) = 0
    AND (
    s.hot_score < #{lastHotScore}
    OR (
    s.hot_score = #{lastHotScore}
    AND s.create_time < #{lastCreateTime}
    )
    OR (
    s.hot_score = #{lastHotScore}
    AND s.create_time = #{lastCreateTime}
    AND s.comment_id < #{lastCommentId}
    )
    )


ORDER BY
COALESCE(c.is_top, 0) DESC,
s.hot_score DESC,
s.create_time DESC,
s.comment_id DESC

LIMIT #{pageSize}
